import { IMessageComposer } from '../../../../../core/communication/messages/IMessageComposer';

export class ReportPoliceCallComposer
    implements IMessageComposer<ConstructorParameters<any>>
{
    private _data: any[];

    constructor(username: string, virtualRoomId: number, note: string) {
        this._data = [username, virtualRoomId, note || ''];
    }

    public getMessageArray() {
        return this._data;
    }
    public dispose(): void {
        this._data = null as any;
    }
}
